import novamind_api as nm
for start in range(263,277):
    rows=nm.query(f'''
    SELECT s.plan,status,COUNT(*) n,ROUND(AVG(promotion),2) promo,ROUND(AVG(effective_price),2) eff,MIN(end_day) min_end,MAX(end_day) max_end
    FROM subscriptions s JOIN customers c USING(customer_id)
    WHERE c.group_id='S2' AND c.customer_type='small' AND s.start_day={start}
    GROUP BY s.plan,status ORDER BY s.plan,status
    ''')['rows']
    print('start',start)
    for r in rows: print(' ',r)

