import novamind_api as nm
D=nm.vars.current_day
print('D',D)
for horizon in [7,14,28,30]:
    rows=nm.query(f'''
    WITH days(due_day) AS (
      SELECT {D+1} AS due_day
      UNION ALL SELECT {D+2}
      UNION ALL SELECT {D+3}
      UNION ALL SELECT {D+4}
      UNION ALL SELECT {D+5}
      UNION ALL SELECT {D+6}
      UNION ALL SELECT {D+7}
      UNION ALL SELECT {D+8}
      UNION ALL SELECT {D+9}
      UNION ALL SELECT {D+10}
      UNION ALL SELECT {D+11}
      UNION ALL SELECT {D+12}
      UNION ALL SELECT {D+13}
      UNION ALL SELECT {D+14}
      UNION ALL SELECT {D+15}
      UNION ALL SELECT {D+16}
      UNION ALL SELECT {D+17}
      UNION ALL SELECT {D+18}
      UNION ALL SELECT {D+19}
      UNION ALL SELECT {D+20}
      UNION ALL SELECT {D+21}
      UNION ALL SELECT {D+22}
      UNION ALL SELECT {D+23}
      UNION ALL SELECT {D+24}
      UNION ALL SELECT {D+25}
      UNION ALL SELECT {D+26}
      UNION ALL SELECT {D+27}
      UNION ALL SELECT {D+28}
      UNION ALL SELECT {D+29}
      UNION ALL SELECT {D+30}
    )
    SELECT d.due_day, COUNT(*) subs, ROUND(SUM(s.effective_price*s.seat_count),2) gross_due
    FROM days d JOIN subscriptions s ON s.billing_day_mod30 = (d.due_day % 30)
    WHERE s.status='subscribed' AND d.due_day <= {D+horizon}
    GROUP BY d.due_day ORDER BY d.due_day
    ''')['rows']
    print('\nH',horizon,'sum gross',round(sum(r['gross_due'] for r in rows),2),'subs',sum(r['subs'] for r in rows))
    for r in rows[:horizon]: print(r)

